import type { Metadata } from "next";
import Returns from "./Returns";

export const metadata: Metadata = {
  title: "返品 / 払戻処理 | ぐんじょうストア POS",
  description:
    "返品・払戻処理の画面。レシート番号 / 取引番号 / バーコードのスキャン照合で元取引を呼び出し、店舗・レジ・日時・元取引番号・支払方法・元合計のヘッダを表示。商品明細ごとに返品数量(0..購入数量)・返品理由(不良品 / サイズ・色違い / お客様都合 / 誤購入 / 期限切れ)・返金額(単価×返品数量)を編集する部分返品グリッド、返品商品計−値引き按分の返金合計と内消費税戻し(軽減/標準)を符号付きで示す返金計算、現金 / クレジット取消 / 電子マネー / 商品券 / ストアクレジットの払戻方法(元支払方法による制約)、良品→在庫戻し / 不良→返品在庫の在庫戻し区分、高額返金・ノーレシート時の責任者承認ゲート、返品確定 / 一時保存 / 返品レシート印刷を備えた払戻ツールです。",
};

export default function ReturnsPage() {
  return <Returns />;
}

// Domain model + pure refund math for the 返品 / 払戻処理 screen.
// Kept framework-free so the math is unit-checkable and the UI stays thin.

export type TaxClass = "standard" | "reduced"; // 標準10% / 軽減8%

export const TAX_RATE: Record<TaxClass, number> = {
  standard: 0.1,
  reduced: 0.08,
};

export const TAX_CLASS_LABEL: Record<TaxClass, string> = {
  standard: "標準 10%",
  reduced: "軽減 8%",
};

// 返品理由コード (per-line)
export type ReasonCode =
  | "defective" // 不良品
  | "wrong-variant" // サイズ・色違い
  | "customer" // お客様都合
  | "mistake" // 誤購入
  | "expired"; // 期限切れ

export const REASON_LABEL: Record<ReasonCode, string> = {
  defective: "不良品",
  "wrong-variant": "サイズ・色違い",
  customer: "お客様都合",
  mistake: "誤購入",
  expired: "期限切れ",
};

export const REASON_OPTIONS: { value: ReasonCode; label: string }[] = (
  Object.keys(REASON_LABEL) as ReasonCode[]
).map((value) => ({ value, label: REASON_LABEL[value] }));

// Reasons whose default restock disposition is 廃棄/返送 (not back to sellable stock)
export const REASON_DEFECTIVE: ReasonCode[] = ["defective", "expired"];

// 在庫戻し区分
export type Disposition = "restock" | "quarantine"; // 良品→在庫戻し / 不良→返品在庫

export const DISPOSITION_LABEL: Record<Disposition, string> = {
  restock: "良品 → 在庫戻し",
  quarantine: "不良 → 返品在庫(廃棄・返送)",
};

// 払戻方法 (refund tender)
export type RefundTender =
  | "cash" // 現金
  | "credit-void" // クレジット取消（元カードへ）
  | "emoney" // 電子マネー
  | "voucher" // 商品券
  | "store-credit"; // ストアクレジット(返品控)

export const TENDER_LABEL: Record<RefundTender, string> = {
  cash: "現金",
  "credit-void": "クレジット取消（元カードへ）",
  emoney: "電子マネー",
  voucher: "商品券",
  "store-credit": "ストアクレジット(返品控)",
};

// Original payment method on the sale (constrains refund tender)
export type OriginalPayment = "cash" | "credit" | "emoney" | "voucher" | "qr";

export const ORIGINAL_PAYMENT_LABEL: Record<OriginalPayment, string> = {
  cash: "現金",
  credit: "クレジットカード",
  emoney: "電子マネー",
  voucher: "商品券",
  qr: "QR決済",
};

// Which refund tenders are *allowed* for a given original payment.
// Rule of thumb in JP retail: card sales must be voided back to the original card
// (no cash back); store credit is always allowed as a fallback.
export const ALLOWED_TENDERS: Record<OriginalPayment, RefundTender[]> = {
  cash: ["cash", "store-credit", "voucher"],
  credit: ["credit-void", "store-credit"],
  emoney: ["emoney", "store-credit"],
  voucher: ["voucher", "store-credit"],
  qr: ["store-credit", "emoney"],
};

export interface OriginalLine {
  id: string;
  name: string;
  sku: string;
  unitPrice: number; // 単価 (tax-inclusive, 円)
  qtyPurchased: number; // 購入数量
  taxClass: TaxClass;
}

export interface OriginalSale {
  receiptNo: string; // レシート番号
  txNo: string; // 取引番号
  barcode: string; // バーコード(取引)
  store: string;
  register: string;
  datetime: string; // 日時
  cashier: string;
  payment: OriginalPayment; // 元支払方法
  // pre-tax discount applied to the whole sale, allocated proportionally (値引き按分)
  saleDiscount: number;
  lines: OriginalLine[];
}

// ─── Sample originals, keyed by every lookup token that resolves to them ───
const SALE_A: OriginalSale = {
  receiptNo: "R-20260618-0042",
  txNo: "TX-883120",
  barcode: "4901234567894",
  store: "ぐんじょう 渋谷店",
  register: "レジ 02",
  datetime: "2026-06-18 14:32",
  cashier: "佐藤 (#118)",
  payment: "credit",
  saleDiscount: 500,
  lines: [
    { id: "l1", name: "オーガニックコットン Tシャツ (白/M)", sku: "AP-TS-WH-M", unitPrice: 3200, qtyPurchased: 2, taxClass: "standard" },
    { id: "l2", name: "リネンブレンド ストール", sku: "AP-ST-NV", unitPrice: 4800, qtyPurchased: 1, taxClass: "standard" },
    { id: "l3", name: "ドリップコーヒー 12袋", sku: "GR-CF-12", unitPrice: 1280, qtyPurchased: 3, taxClass: "reduced" },
  ],
};

const SALE_B: OriginalSale = {
  receiptNo: "R-20260620-0117",
  txNo: "TX-884050",
  barcode: "4900000000017",
  store: "ぐんじょう 渋谷店",
  register: "レジ 01",
  datetime: "2026-06-20 11:05",
  cashier: "鈴木 (#204)",
  payment: "cash",
  saleDiscount: 0,
  lines: [
    { id: "m1", name: "ステンレスタンブラー 480ml", sku: "HG-TB-480", unitPrice: 2480, qtyPurchased: 1, taxClass: "standard" },
    { id: "m2", name: "焼き菓子アソート 6個", sku: "GR-BK-06", unitPrice: 1620, qtyPurchased: 2, taxClass: "reduced" },
  ],
};

const SALE_DB: OriginalSale[] = [SALE_A, SALE_B];

/** Resolve a lookup token (receipt no / tx no / barcode, case-insensitive) to a sale. */
export function lookupSale(token: string): OriginalSale | null {
  const t = token.trim().toLowerCase();
  if (!t) return null;
  return (
    SALE_DB.find(
      (s) =>
        s.receiptNo.toLowerCase() === t ||
        s.txNo.toLowerCase() === t ||
        s.barcode.toLowerCase() === t
    ) ?? null
  );
}

export const SAMPLE_TOKENS = [SALE_A.receiptNo, SALE_B.barcode, SALE_B.txNo];

// ─── Working return-line state ───
export interface ReturnLine extends OriginalLine {
  qtyReturn: number; // 返品数量 0..qtyPurchased
  reason: ReasonCode | ""; // per-line 返品理由 ("" until chosen)
  disposition: Disposition; // 在庫戻し区分
}

export function toReturnLines(sale: OriginalSale): ReturnLine[] {
  return sale.lines.map((l) => ({
    ...l,
    qtyReturn: 0,
    reason: "",
    disposition: "restock",
  }));
}

// ─── Refund math (all pure) ───

/** 返金額 / line = 単価 × 返品数量 (tax-inclusive unit price). */
export function lineRefund(line: { unitPrice: number; qtyReturn: number }): number {
  return line.unitPrice * line.qtyReturn;
}

/** Σ line refunds (tax-inclusive). */
export function grossReturned(lines: ReturnLine[]): number {
  return lines.reduce((sum, l) => sum + lineRefund(l), 0);
}

/**
 * 値引き按分: the sale-level discount is allocated to returned value in
 * proportion to (returned value / original sale subtotal). Returned to the
 * customer means we claw the discount back, so it REDUCES the refund.
 */
export function allocatedDiscount(sale: OriginalSale, lines: ReturnLine[]): number {
  if (sale.saleDiscount <= 0) return 0;
  const originalSubtotal = sale.lines.reduce(
    (s, l) => s + l.unitPrice * l.qtyPurchased,
    0
  );
  if (originalSubtotal <= 0) return 0;
  const returnedValue = grossReturned(lines);
  return Math.round(sale.saleDiscount * (returnedValue / originalSubtotal));
}

/**
 * 消費税戻し: the tax portion baked into the (net of allocated discount)
 * returned amount, split by tax class. Unit prices are tax-INCLUSIVE, so the
 * embedded tax for a line at rate r is amount × r/(1+r). We surface it as a
 * line item even though it's already inside the gross — retail 返品レシート
 * shows 内消費税戻し explicitly (軽減 / 標準).
 */
export function taxReversed(sale: OriginalSale, lines: ReturnLine[]): {
  standard: number;
  reduced: number;
  total: number;
} {
  const disc = allocatedDiscount(sale, lines);
  const gross = grossReturned(lines);
  // discount reduces each line's contribution proportionally
  const factor = gross > 0 ? (gross - disc) / gross : 0;
  let standard = 0;
  let reduced = 0;
  for (const l of lines) {
    const net = lineRefund(l) * factor;
    const r = TAX_RATE[l.taxClass];
    const tax = (net * r) / (1 + r);
    if (l.taxClass === "standard") standard += tax;
    else reduced += tax;
  }
  standard = Math.round(standard);
  reduced = Math.round(reduced);
  return { standard, reduced, total: standard + reduced };
}

/**
 * 返金合計 = 返品商品計 − 値引き按分. (Tax is embedded in the tax-inclusive
 * unit prices, so it is part of the gross, not added on top — `taxReversed`
 * is the explanatory breakdown of what tax sits inside this amount.)
 */
export function refundTotal(sale: OriginalSale, lines: ReturnLine[]): number {
  return grossReturned(lines) - allocatedDiscount(sale, lines);
}

// ─── Approval gating ───
export const APPROVAL_THRESHOLD = 10000; // 返金が ¥10,000 超で承認必須

export interface ValidationState {
  hasReturnQty: boolean; // ≥1 line with qtyReturn > 0
  reasonsComplete: boolean; // every returning line has a reason
  qtyWithinPurchased: boolean; // no line returns more than purchased
  tenderChosen: boolean;
  tenderAllowed: boolean; // chosen tender ∈ allowed for original payment
  approvalRequired: boolean; // high-value OR no-receipt
  approvalGiven: boolean;
}

export function validate(
  sale: OriginalSale | null,
  lines: ReturnLine[],
  tender: RefundTender | "",
  noReceipt: boolean,
  approval: { manager: string; pin: string }
): ValidationState {
  const returningLines = lines.filter((l) => l.qtyReturn > 0);
  const total = sale ? refundTotal(sale, lines) : 0;
  const tenderChosen = tender !== "";
  const tenderAllowed =
    !sale || !tenderChosen ? true : ALLOWED_TENDERS[sale.payment].includes(tender as RefundTender);
  const approvalRequired = total > APPROVAL_THRESHOLD || noReceipt;
  const approvalGiven = approval.manager.trim().length > 0 && approval.pin.trim().length >= 4;
  return {
    hasReturnQty: returningLines.length > 0,
    reasonsComplete: returningLines.every((l) => l.reason !== ""),
    qtyWithinPurchased: lines.every(
      (l) => l.qtyReturn >= 0 && l.qtyReturn <= l.qtyPurchased
    ),
    tenderChosen,
    tenderAllowed,
    approvalRequired,
    approvalGiven,
  };
}

export function canProcess(v: ValidationState): boolean {
  return (
    v.hasReturnQty &&
    v.reasonsComplete &&
    v.qtyWithinPurchased &&
    v.tenderChosen &&
    v.tenderAllowed &&
    (!v.approvalRequired || v.approvalGiven)
  );
}

"use client";

import * as React from "react";
import {
  IconBarcode,
  IconBuildingStore,
  IconCashRegister,
  IconClock,
  IconReceipt2,
  IconCreditCard,
  IconSearch,
  IconScan,
  IconPrinter,
  IconDeviceFloppy,
  IconArrowBackUp,
  IconCheck,
  IconAlertTriangle,
  IconShieldLock,
  IconPackageImport,
  IconX,
} from "@tabler/icons-react";
import {
  Alert,
  AlertDescription,
  AlertTitle,
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  CurrencyInput,
  Delta,
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  EditableDataTable,
  Input,
  Label,
  NumberInput,
  RevealSection,
  ApprovalSteps,
  Select,
  Separator,
  Statistic,
  Textarea,
  formatCurrency,
  formatNumber,
  type EditableColumn,
  type ApprovalStep,
} from "@gunjo/ui";

import {
  ALLOWED_TENDERS,
  APPROVAL_THRESHOLD,
  DISPOSITION_LABEL,
  ORIGINAL_PAYMENT_LABEL,
  REASON_DEFECTIVE,
  REASON_LABEL,
  REASON_OPTIONS,
  SAMPLE_TOKENS,
  TAX_CLASS_LABEL,
  TENDER_LABEL,
  allocatedDiscount,
  canProcess,
  grossReturned,
  lineRefund,
  lookupSale,
  refundTotal,
  taxReversed,
  toReturnLines,
  validate,
  type Disposition,
  type OriginalSale,
  type ReasonCode,
  type RefundTender,
  type ReturnLine,
} from "./data";

const yen = (n: number) => formatCurrency(n, { maximumFractionDigits: 0 });

type Phase = "lookup" | "editing" | "done";

const DISPOSITION_OPTIONS: { value: Disposition; label: string }[] = (
  Object.keys(DISPOSITION_LABEL) as Disposition[]
).map((value) => ({ value, label: DISPOSITION_LABEL[value] }));

export default function Returns() {
  const [phase, setPhase] = React.useState<Phase>("lookup");
  const [token, setToken] = React.useState("");
  const [lookupError, setLookupError] = React.useState<string | null>(null);
  const [noReceipt, setNoReceipt] = React.useState(false);

  const [sale, setSale] = React.useState<OriginalSale | null>(null);
  const [lines, setLines] = React.useState<ReturnLine[]>([]);
  const [tender, setTender] = React.useState<RefundTender | "">("");
  const [memo, setMemo] = React.useState("");
  const [approval, setApproval] = React.useState({ manager: "", pin: "" });
  const [approvalConfirmed, setApprovalConfirmed] = React.useState(false);
  const [receiptOpen, setReceiptOpen] = React.useState(false);
  const [showErrors, setShowErrors] = React.useState(false);

  // ─── lookup ───
  function resolve(value: string) {
    const found = lookupSale(value);
    if (!found) {
      setLookupError(
        `「${value}」に一致する取引が見つかりません。レシート番号 / 取引番号 / バーコードを確認してください。`
      );
      return;
    }
    setSale(found);
    setLines(toReturnLines(found));
    setTender(found.payment === "cash" ? "cash" : found.payment === "credit" ? "credit-void" : "");
    setLookupError(null);
    setShowErrors(false);
    setApprovalConfirmed(false);
    setPhase("editing");
  }

  function startNoReceipt() {
    // ノーレシート: synthesise a minimal manual sale shell (manager-gated, store credit only)
    const shell: OriginalSale = {
      receiptNo: "—（レシート無し）",
      txNo: "MANUAL",
      barcode: "—",
      store: "ぐんじょう 渋谷店",
      register: "レジ —",
      datetime: new Date().toISOString().slice(0, 16).replace("T", " "),
      cashier: "—",
      payment: "voucher",
      saleDiscount: 0,
      lines: [
        { id: "n1", name: "（手入力）返品商品", sku: "MANUAL", unitPrice: 0, qtyPurchased: 1, taxClass: "standard" },
      ],
    };
    setSale(shell);
    setLines(toReturnLines(shell));
    setTender("store-credit");
    setNoReceipt(true);
    setLookupError(null);
    setShowErrors(false);
    setApprovalConfirmed(false);
    setPhase("editing");
  }

  function reset() {
    setPhase("lookup");
    setSale(null);
    setLines([]);
    setToken("");
    setTender("");
    setMemo("");
    setNoReceipt(false);
    setApproval({ manager: "", pin: "" });
    setApprovalConfirmed(false);
    setShowErrors(false);
  }

  // ─── line mutation ───
  function patchLine(id: string, patch: Partial<ReturnLine>) {
    setLines((prev) =>
      prev.map((l) => {
        if (l.id !== id) return l;
        const next = { ...l, ...patch };
        // when a reason is set, default disposition from the reason category
        if (patch.reason !== undefined && patch.reason !== "") {
          next.disposition = REASON_DEFECTIVE.includes(patch.reason as ReasonCode)
            ? "quarantine"
            : "restock";
        }
        return next;
      })
    );
  }

  // ─── derived ───
  const gross = sale ? grossReturned(lines) : 0;
  const disc = sale ? allocatedDiscount(sale, lines) : 0;
  const tax = sale ? taxReversed(sale, lines) : { standard: 0, reduced: 0, total: 0 };
  const total = sale ? refundTotal(sale, lines) : 0;
  const v = validate(sale, lines, tender, noReceipt, approval);
  const ready = canProcess(v);
  const returningCount = lines.filter((l) => l.qtyReturn > 0).length;
  const allowedTenders: RefundTender[] = sale ? ALLOWED_TENDERS[sale.payment] : [];

  // approval is only "given" once the manager has explicitly confirmed
  const approvalSatisfied = !v.approvalRequired || (v.approvalGiven && approvalConfirmed);
  const processable = ready && approvalSatisfied;

  function process() {
    if (!processable) {
      setShowErrors(true);
      return;
    }
    setPhase("done");
  }

  // ─── columns for the returnable-lines grid ───
  const columns: EditableColumn<ReturnLine>[] = [
    {
      id: "name",
      header: "商品 / SKU",
      minWidth: "12rem",
      cell: (row) => (
        <div className="flex flex-col">
          <span className="font-medium leading-snug">{row.name}</span>
          <span className="text-xs text-muted-foreground tabular-nums">
            {row.sku} · {TAX_CLASS_LABEL[row.taxClass]}
          </span>
        </div>
      ),
    },
    {
      id: "unitPrice",
      header: "単価",
      align: "right",
      width: "6rem",
      cell: (row, ctx) =>
        noReceipt ? (
          <CurrencyInput
            value={row.unitPrice}
            min={0}
            onValueChange={(n) => patchLine(row.id, { unitPrice: n ?? 0 })}
            aria-label={ctx.ariaLabel}
            className="h-8"
          />
        ) : (
          <span className="tabular-nums">{yen(row.unitPrice)}</span>
        ),
    },
    {
      id: "qtyPurchased",
      header: "購入数量",
      align: "center",
      width: "5rem",
      cell: (row) =>
        noReceipt ? (
          <NumberInput
            layout="stepper"
            value={row.qtyPurchased}
            min={1}
            max={99}
            onValueChange={(n) =>
              patchLine(row.id, {
                qtyPurchased: n,
                qtyReturn: Math.min(row.qtyReturn, n),
              })
            }
            aria-label={`${row.name} 購入数量`}
          />
        ) : (
          <span className="tabular-nums">{formatNumber(row.qtyPurchased)}</span>
        ),
    },
    {
      id: "qtyReturn",
      header: "返品数量",
      align: "center",
      width: "9rem",
      minWidth: "8rem",
      cell: (row, ctx) => (
        <NumberInput
          layout="stepper"
          value={row.qtyReturn}
          min={0}
          max={row.qtyPurchased}
          onValueChange={(n) => patchLine(row.id, { qtyReturn: n })}
          aria-label={`${ctx.ariaLabel}（0〜${row.qtyPurchased}）`}
        />
      ),
    },
    {
      id: "reason",
      header: "返品理由",
      minWidth: "10rem",
      cell: (row, ctx) => {
        const needsReason = row.qtyReturn > 0 && row.reason === "";
        return (
          <Select
            value={row.reason}
            onChange={(e) => patchLine(row.id, { reason: e.target.value as ReasonCode | "" })}
            aria-label={ctx.ariaLabel}
            aria-invalid={showErrors && needsReason ? true : undefined}
            disabled={row.qtyReturn === 0}
            className="h-8"
          >
            <option value="">{row.qtyReturn === 0 ? "—" : "理由を選択"}</option>
            {REASON_OPTIONS.map((o) => (
              <option key={o.value} value={o.value}>
                {o.label}
              </option>
            ))}
          </Select>
        );
      },
    },
    {
      id: "disposition",
      header: "在庫戻し",
      minWidth: "11rem",
      cell: (row, ctx) => (
        <Select
          value={row.disposition}
          onChange={(e) => patchLine(row.id, { disposition: e.target.value as Disposition })}
          aria-label={`${row.name} 在庫戻し区分`}
          disabled={row.qtyReturn === 0}
          className="h-8"
        >
          {DISPOSITION_OPTIONS.map((o) => (
            <option key={o.value} value={o.value}>
              {o.label}
            </option>
          ))}
        </Select>
      ),
    },
    {
      id: "refund",
      header: "返金額",
      align: "right",
      width: "7rem",
      cell: (row) => {
        const amt = lineRefund(row);
        if (amt === 0) return <span className="text-muted-foreground tabular-nums">—</span>;
        // refund = money out to customer → negative movement
        return (
          <Delta
            value={-amt}
            format={(n) => yen(Math.abs(n))}
            labels={{ negative: "返金" }}
            hideArrow
          />
        );
      },
    },
  ];

  // ─── per-column footer (totals row) ───
  function footerCell(col: EditableColumn<ReturnLine>) {
    if (col.id === "name") return <span className="font-semibold">返品商品計</span>;
    if (col.id === "qtyReturn") {
      const q = lines.reduce((s, l) => s + l.qtyReturn, 0);
      return <span className="font-semibold tabular-nums">{formatNumber(q)} 点</span>;
    }
    if (col.id === "refund") {
      if (gross === 0) return <span className="text-muted-foreground">—</span>;
      return (
        <Delta
          value={-gross}
          format={(n) => yen(Math.abs(n))}
          labels={{ negative: "返金" }}
          hideArrow
          className="font-semibold"
        />
      );
    }
    return null;
  }

  // ─── approval trail steps ───
  const approvalSteps: ApprovalStep[] = [
    {
      label: "レジ担当（申請）",
      state: "approved",
      actor: "佐藤 (#118)",
      timestamp: "ただ今",
    },
    {
      label: noReceipt ? "責任者承認（ノーレシート）" : `責任者承認（返金 ${yen(APPROVAL_THRESHOLD)} 超）`,
      state: approvalSatisfied
        ? "approved"
        : v.approvalGiven
        ? "current"
        : "pending",
      actor: approval.manager.trim() || undefined,
      comment: approvalSatisfied ? undefined : "責任者IDと承認PIN(4桁以上)を入力し、承認してください。",
    },
  ];

  return (
    <main className="mx-auto w-full max-w-screen-xl px-4 py-6 sm:px-6 lg:px-8">
      {/* ───────── Header ───────── */}
      <header className="flex flex-col gap-4">
        <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
          <div className="flex flex-col gap-1">
            <h1 className="flex items-center gap-2 text-2xl font-bold tracking-tight">
              <IconArrowBackUp className="h-6 w-6 shrink-0 text-muted-foreground" aria-hidden />
              返品 / 払戻処理
            </h1>
            <p className="text-sm text-muted-foreground">
              元取引を照合し、返品する商品と数量・理由を選んで返金額を算出します。
            </p>
          </div>
          <div className="flex items-center gap-2" aria-live="polite">
            {phase === "lookup" && (
              <Badge variant="outline">
                <IconSearch className="mr-1 h-3.5 w-3.5" aria-hidden />
                取引照合待ち
              </Badge>
            )}
            {phase === "editing" && (
              <Badge variant={noReceipt ? "warning" : "info"}>
                <IconReceipt2 className="mr-1 h-3.5 w-3.5" aria-hidden />
                {noReceipt ? "ノーレシート返品" : "返品処理中"}
              </Badge>
            )}
            {phase === "done" && (
              <Badge variant="success">
                <IconCheck className="mr-1 h-3.5 w-3.5" aria-hidden />
                返品完了
              </Badge>
            )}
          </div>
        </div>
      </header>

      {/* ───────── Phase: lookup (empty state) ───────── */}
      {phase === "lookup" && (
        <LookupPanel
          token={token}
          setToken={setToken}
          error={lookupError}
          onResolve={resolve}
          onNoReceipt={startNoReceipt}
        />
      )}

      {/* ───────── Phase: editing ───────── */}
      {phase === "editing" && sale && (
        <div className="mt-6 grid grid-cols-1 gap-6 lg:grid-cols-[minmax(0,1fr)_22rem]">
          {/* LEFT column */}
          <div className="flex flex-col gap-6">
            {/* Original sale header */}
            <Card>
              <CardHeader className="flex flex-row items-start justify-between gap-3 space-y-0">
                <div>
                  <CardTitle className="text-base">元取引</CardTitle>
                  <CardDescription>照合された元の販売取引</CardDescription>
                </div>
                <Button variant="ghost" size="sm" onClick={reset}>
                  <IconX className="h-4 w-4" aria-hidden />
                  別の取引を照合
                </Button>
              </CardHeader>
              <CardContent>
                <dl className="grid grid-cols-2 gap-x-4 gap-y-3 sm:grid-cols-3">
                  <Field icon={<IconBuildingStore className="h-4 w-4" />} label="店舗" value={sale.store} />
                  <Field icon={<IconCashRegister className="h-4 w-4" />} label="レジ" value={sale.register} />
                  <Field icon={<IconClock className="h-4 w-4" />} label="日時" value={sale.datetime} />
                  <Field icon={<IconReceipt2 className="h-4 w-4" />} label="元取引番号" value={sale.txNo} />
                  <Field
                    icon={<IconCreditCard className="h-4 w-4" />}
                    label="支払方法"
                    value={ORIGINAL_PAYMENT_LABEL[sale.payment]}
                  />
                  <Field
                    icon={<IconBarcode className="h-4 w-4" />}
                    label="元合計"
                    value={yen(
                      sale.lines.reduce((s, l) => s + l.unitPrice * l.qtyPurchased, 0) - sale.saleDiscount
                    )}
                  />
                </dl>
              </CardContent>
            </Card>

            {noReceipt && (
              <Alert variant="warning">
                <IconAlertTriangle className="h-4 w-4" aria-hidden />
                <AlertTitle>ノーレシート返品</AlertTitle>
                <AlertDescription>
                  レシートが無いため商品・単価・数量を手入力し、責任者承認が必須です。払戻はストアクレジット(返品控)に限定されます。
                </AlertDescription>
              </Alert>
            )}

            {/* Returnable lines */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">返品明細</CardTitle>
                <CardDescription>
                  返品する商品の数量(0〜購入数量)と理由を選択します。部分返品が可能です。
                </CardDescription>
              </CardHeader>
              <CardContent>
                <EditableDataTable
                  columns={columns}
                  rows={lines}
                  getRowId={(r) => r.id}
                  caption="返品明細グリッド：商品ごとに返品数量・理由・在庫戻し区分を入力すると返金額が算出されます"
                  rowLabel={(i) => lines[i]?.name ?? `行 ${i + 1}`}
                  getRowError={(row) =>
                    showErrors && row.qtyReturn > 0 && row.reason === ""
                      ? "返品理由を選択してください"
                      : undefined
                  }
                  renderFooterCell={footerCell}
                />
              </CardContent>
            </Card>

            {/* Validation alert */}
            {showErrors && !processable && (
              <Alert variant="destructive">
                <IconAlertTriangle className="h-4 w-4" aria-hidden />
                <AlertTitle>返品確定の前に確認が必要です</AlertTitle>
                <AlertDescription>
                  <ul className="list-disc space-y-0.5 pl-4">
                    {!v.hasReturnQty && <li>返品数量が 1 以上の商品がありません。</li>}
                    {v.hasReturnQty && !v.reasonsComplete && <li>返品する商品の返品理由が未選択です。</li>}
                    {!v.tenderChosen && <li>払戻方法が未選択です。</li>}
                    {v.tenderChosen && !v.tenderAllowed && (
                      <li>選択した払戻方法は元支払方法では使用できません。</li>
                    )}
                    {v.approvalRequired && !approvalSatisfied && (
                      <li>責任者承認が必要です（責任者ID + PIN を入力し承認）。</li>
                    )}
                  </ul>
                </AlertDescription>
              </Alert>
            )}
          </div>

          {/* RIGHT column — refund summary + tender + approval + actions */}
          <aside className="flex flex-col gap-6">
            {/* Refund summary */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">返金計算</CardTitle>
                <CardDescription>返品商品計 − 値引き按分 = 返金合計</CardDescription>
              </CardHeader>
              <CardContent className="flex flex-col gap-3">
                <SummaryRow label="返品商品計" value={yen(gross)} />
                {disc > 0 && (
                  <SummaryRow
                    label="値引き按分"
                    valueNode={
                      <Delta
                        value={-disc}
                        format={(n) => yen(Math.abs(n))}
                        labels={{ negative: "差引" }}
                        hideArrow
                      />
                    }
                  />
                )}
                <Separator />
                <div className="flex flex-col gap-1 rounded-md bg-muted/40 px-3 py-2 text-xs text-muted-foreground">
                  <span className="font-medium text-foreground">内消費税戻し</span>
                  <div className="flex justify-between tabular-nums">
                    <span>標準 10%</span>
                    <span>{yen(tax.standard)}</span>
                  </div>
                  <div className="flex justify-between tabular-nums">
                    <span>軽減 8%</span>
                    <span>{yen(tax.reduced)}</span>
                  </div>
                </div>
                <Separator />
                {/* refund total = money OUT to the customer → negative Delta */}
                <div className="flex items-center justify-between">
                  <span className="text-sm font-medium">返金合計</span>
                  <Delta
                    value={-total}
                    format={(n) => yen(Math.abs(n))}
                    labels={{ negative: "お客様へ返金", zero: "返金なし" }}
                    showLabel={false}
                    hideArrow
                    className="text-xl"
                  />
                </div>
                <Statistic
                  label="返金合計（お客様へ払戻）"
                  value={total === 0 ? "—" : `− ${yen(total)}`}
                  hint={`${returningCount} 品目 / ${lines.reduce((s, l) => s + l.qtyReturn, 0)} 点`}
                  tone="negative"
                />
              </CardContent>
            </Card>

            {/* Refund tender */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">払戻方法</CardTitle>
                <CardDescription>
                  元支払方法「{ORIGINAL_PAYMENT_LABEL[sale.payment]}」に応じた方法のみ選択できます。
                </CardDescription>
              </CardHeader>
              <CardContent className="flex flex-col gap-3">
                <Select
                  label="払戻方法"
                  value={tender}
                  onChange={(e) => setTender(e.target.value as RefundTender | "")}
                  aria-invalid={showErrors && (!v.tenderChosen || !v.tenderAllowed) ? true : undefined}
                >
                  <option value="">払戻方法を選択</option>
                  {(Object.keys(TENDER_LABEL) as RefundTender[]).map((t) => {
                    const allowed = allowedTenders.includes(t);
                    return (
                      <option key={t} value={t} disabled={!allowed}>
                        {TENDER_LABEL[t]}
                        {allowed ? "" : "（元支払方法では不可）"}
                      </option>
                    );
                  })}
                </Select>
                {tender !== "" && v.tenderAllowed && (
                  <div className="flex items-center justify-between rounded-md border px-3 py-2 text-sm">
                    <span className="text-muted-foreground">{TENDER_LABEL[tender]} に返金</span>
                    <Delta
                      value={-total}
                      format={(n) => yen(Math.abs(n))}
                      labels={{ negative: "返金", zero: "返金なし" }}
                      hideArrow
                    />
                  </div>
                )}
                {tender === "credit-void" && (
                  <p className="text-xs text-muted-foreground">
                    元クレジット取引を取消し、同一カードへ返金します。現金での払戻はできません。
                  </p>
                )}
              </CardContent>
            </Card>

            {/* Approval gate (reveals only when required) */}
            <RevealSection
              open={v.approvalRequired}
              label="責任者承認"
              className="rounded-lg border border-warning-border bg-warning-subtle/40 p-4"
            >
              <div className="flex flex-col gap-3">
                <div className="flex items-start gap-2">
                  <IconShieldLock className="mt-0.5 h-5 w-5 shrink-0 text-warning" aria-hidden />
                  <div>
                    <p className="text-sm font-semibold">責任者承認が必要です</p>
                    <p className="text-xs text-muted-foreground">
                      {noReceipt
                        ? "ノーレシート返品のため承認が必要です。"
                        : `返金額が ${yen(APPROVAL_THRESHOLD)} を超えるため承認が必要です。`}
                    </p>
                  </div>
                </div>
                <div className="flex flex-col gap-2">
                  <div className="flex flex-col gap-1">
                    <Label htmlFor="mgr-id">責任者ID</Label>
                    <Input
                      id="mgr-id"
                      value={approval.manager}
                      placeholder="例: 田中 (#005)"
                      onChange={(e) => {
                        setApproval((a) => ({ ...a, manager: e.target.value }));
                        setApprovalConfirmed(false);
                      }}
                    />
                  </div>
                  <div className="flex flex-col gap-1">
                    <Label htmlFor="mgr-pin">承認PIN（4桁以上）</Label>
                    <Input
                      id="mgr-pin"
                      type="password"
                      inputMode="numeric"
                      value={approval.pin}
                      placeholder="••••"
                      onChange={(e) => {
                        setApproval((a) => ({ ...a, pin: e.target.value }));
                        setApprovalConfirmed(false);
                      }}
                    />
                  </div>
                  <Button
                    variant={approvalSatisfied ? "success" : "warning"}
                    size="sm"
                    disabled={!v.approvalGiven || approvalConfirmed}
                    onClick={() => setApprovalConfirmed(true)}
                  >
                    {approvalSatisfied ? (
                      <>
                        <IconCheck className="h-4 w-4" aria-hidden />
                        承認済み
                      </>
                    ) : (
                      <>
                        <IconShieldLock className="h-4 w-4" aria-hidden />
                        承認する
                      </>
                    )}
                  </Button>
                </div>
                <Separator />
                <ApprovalSteps steps={approvalSteps} variant="compact" />
              </div>
            </RevealSection>

            {/* Memo + actions */}
            <Card>
              <CardContent className="flex flex-col gap-3 pt-6">
                <div className="flex flex-col gap-1">
                  <Label htmlFor="memo">備考（任意）</Label>
                  <Textarea
                    id="memo"
                    value={memo}
                    onChange={(e) => setMemo(e.target.value)}
                    placeholder="返品の補足メモ"
                    rows={2}
                  />
                </div>
                <Button
                  variant="destructive"
                  onClick={process}
                  aria-disabled={!processable}
                  className="w-full"
                >
                  <IconArrowBackUp className="h-4 w-4" aria-hidden />
                  返品確定（払戻）
                </Button>
                <div className="grid grid-cols-2 gap-2">
                  <Button variant="outline" onClick={() => setReceiptOpen(true)}>
                    <IconPrinter className="h-4 w-4" aria-hidden />
                    返品レシート
                  </Button>
                  <Button variant="ghost">
                    <IconDeviceFloppy className="h-4 w-4" aria-hidden />
                    一時保存
                  </Button>
                </div>
                {!processable && (
                  <p className="text-center text-xs text-muted-foreground" aria-live="polite">
                    返品数量・理由・払戻方法
                    {v.approvalRequired ? "・責任者承認" : ""}が揃うと確定できます。
                  </p>
                )}
              </CardContent>
            </Card>
          </aside>
        </div>
      )}

      {/* ───────── Phase: done ───────── */}
      {phase === "done" && sale && (
        <DonePanel
          sale={sale}
          lines={lines}
          total={total}
          tender={tender as RefundTender}
          noReceipt={noReceipt}
          onPrint={() => setReceiptOpen(true)}
          onReset={reset}
        />
      )}

      {/* ───────── Receipt preview dialog ───────── */}
      {sale && (
        <Dialog open={receiptOpen} onOpenChange={setReceiptOpen}>
          <DialogContent className="max-w-sm">
            <DialogHeader>
              <DialogTitle>返品レシート（プレビュー）</DialogTitle>
              <DialogDescription>確定前のプレビューです。</DialogDescription>
            </DialogHeader>
            <ReceiptBody
              sale={sale}
              lines={lines}
              gross={gross}
              disc={disc}
              tax={tax}
              total={total}
              tender={tender as RefundTender}
            />
            <DialogFooter>
              <Button variant="outline" onClick={() => setReceiptOpen(false)}>
                閉じる
              </Button>
              <Button onClick={() => setReceiptOpen(false)}>
                <IconPrinter className="h-4 w-4" aria-hidden />
                印刷
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      )}
    </main>
  );
}

// ───────────────────────── sub-components ─────────────────────────

function Field({
  icon,
  label,
  value,
}: {
  icon: React.ReactNode;
  label: string;
  value: React.ReactNode;
}) {
  return (
    <div className="flex flex-col gap-0.5">
      <dt className="flex items-center gap-1 text-xs text-muted-foreground">
        <span className="text-muted-foreground" aria-hidden>
          {icon}
        </span>
        {label}
      </dt>
      <dd className="text-sm font-medium tabular-nums">{value}</dd>
    </div>
  );
}

function SummaryRow({
  label,
  value,
  valueNode,
}: {
  label: string;
  value?: string;
  valueNode?: React.ReactNode;
}) {
  return (
    <div className="flex items-center justify-between text-sm">
      <span className="text-muted-foreground">{label}</span>
      {valueNode ?? <span className="tabular-nums">{value}</span>}
    </div>
  );
}

function LookupPanel({
  token,
  setToken,
  error,
  onResolve,
  onNoReceipt,
}: {
  token: string;
  setToken: (v: string) => void;
  error: string | null;
  onResolve: (v: string) => void;
  onNoReceipt: () => void;
}) {
  const inputRef = React.useRef<HTMLInputElement>(null);
  return (
    <Card className="mt-6">
      <CardHeader>
        <CardTitle className="flex items-center gap-2 text-base">
          <IconScan className="h-5 w-5 text-muted-foreground" aria-hidden />
          元取引の照合
        </CardTitle>
        <CardDescription>
          レシート番号 / 取引番号 / バーコードをスキャン、または入力して元の販売取引を呼び出します。
        </CardDescription>
      </CardHeader>
      <CardContent className="flex flex-col gap-4">
        <form
          className="flex flex-col gap-2 sm:flex-row"
          onSubmit={(e) => {
            e.preventDefault();
            onResolve(token);
          }}
        >
          <div className="flex flex-1 flex-col gap-1">
            <Label htmlFor="lookup-token">レシート番号 / 取引番号 / バーコード</Label>
            <div className="relative">
              <IconBarcode
                className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground"
                aria-hidden
              />
              <Input
                id="lookup-token"
                ref={inputRef}
                value={token}
                onChange={(e) => setToken(e.target.value)}
                placeholder="スキャン または 入力（例: R-20260618-0042）"
                autoComplete="off"
                inputMode="text"
                aria-invalid={error ? true : undefined}
                aria-describedby={error ? "lookup-error" : undefined}
                className="pl-9"
              />
            </div>
          </div>
          <div className="flex items-end">
            <Button type="submit" className="w-full sm:w-auto">
              <IconSearch className="h-4 w-4" aria-hidden />
              取引を照合
            </Button>
          </div>
        </form>

        {error && (
          <Alert variant="destructive" id="lookup-error">
            <IconAlertTriangle className="h-4 w-4" aria-hidden />
            <AlertTitle>取引が見つかりません</AlertTitle>
            <AlertDescription>{error}</AlertDescription>
          </Alert>
        )}

        {/* empty-state helper */}
        <div className="flex flex-col gap-2 rounded-lg border border-dashed p-4 text-sm text-muted-foreground">
          <p className="flex items-center gap-1.5 font-medium text-foreground">
            <IconScan className="h-4 w-4" aria-hidden />
            取引が読み込まれていません
          </p>
          <p>スキャナで読み取るか、下のサンプルから照合を試せます。</p>
          <div className="flex flex-wrap gap-2 pt-1">
            {SAMPLE_TOKENS.map((t) => (
              <Button
                key={t}
                variant="outline"
                size="sm"
                onClick={() => {
                  setToken(t);
                  onResolve(t);
                }}
              >
                <IconBarcode className="h-3.5 w-3.5" aria-hidden />
                {t}
              </Button>
            ))}
          </div>
        </div>

        <Separator />
        <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
          <p className="text-sm text-muted-foreground">レシートが無い場合は責任者承認のうえ手入力で返品できます。</p>
          <Button variant="ghost" size="sm" onClick={onNoReceipt}>
            <IconReceipt2 className="h-4 w-4" aria-hidden />
            レシート無しで返品（ノーレシート）
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

function ReceiptBody({
  sale,
  lines,
  gross,
  disc,
  tax,
  total,
  tender,
}: {
  sale: OriginalSale;
  lines: ReturnLine[];
  gross: number;
  disc: number;
  tax: { standard: number; reduced: number; total: number };
  total: number;
  tender: RefundTender | "";
}) {
  const returning = lines.filter((l) => l.qtyReturn > 0);
  return (
    <div className="rounded-md border bg-card p-4 font-mono text-xs text-card-foreground">
      <p className="text-center font-semibold">＊ 返品控 ＊</p>
      <p className="text-center text-muted-foreground">{sale.store} / {sale.register}</p>
      <p className="text-center text-muted-foreground">{sale.datetime}</p>
      <Separator className="my-2" />
      <p className="text-muted-foreground">元取引: {sale.txNo}</p>
      <Separator className="my-2" />
      {returning.length === 0 ? (
        <p className="text-muted-foreground">（返品商品なし）</p>
      ) : (
        returning.map((l) => (
          <div key={l.id} className="flex justify-between gap-2">
            <span className="truncate">
              {l.name} ×{l.qtyReturn}
              {l.reason ? `（${REASON_LABEL[l.reason]}）` : ""}
            </span>
            <span className="shrink-0 tabular-nums">-{yen(lineRefund(l))}</span>
          </div>
        ))
      )}
      <Separator className="my-2" />
      <div className="flex justify-between tabular-nums">
        <span>返品商品計</span>
        <span>-{yen(gross)}</span>
      </div>
      {disc > 0 && (
        <div className="flex justify-between tabular-nums">
          <span>値引き按分</span>
          <span>+{yen(disc)}</span>
        </div>
      )}
      <div className="flex justify-between tabular-nums text-muted-foreground">
        <span>内消費税戻し</span>
        <span>-{yen(tax.total)}</span>
      </div>
      <Separator className="my-2" />
      <div className="flex justify-between text-sm font-bold tabular-nums">
        <span>返金合計</span>
        <span>-{yen(total)}</span>
      </div>
      <div className="flex justify-between tabular-nums">
        <span>払戻方法</span>
        <span>{tender ? TENDER_LABEL[tender] : "—"}</span>
      </div>
    </div>
  );
}

function DonePanel({
  sale,
  lines,
  total,
  tender,
  noReceipt,
  onPrint,
  onReset,
}: {
  sale: OriginalSale;
  lines: ReturnLine[];
  total: number;
  tender: RefundTender;
  noReceipt: boolean;
  onPrint: () => void;
  onReset: () => void;
}) {
  const returning = lines.filter((l) => l.qtyReturn > 0);
  const refundNo = `RT-${sale.txNo.replace(/[^0-9]/g, "").slice(-6) || "000000"}`;
  return (
    <div className="mt-6 flex flex-col gap-6">
      <Alert variant="success">
        <IconCheck className="h-4 w-4" aria-hidden />
        <AlertTitle>返品が完了しました</AlertTitle>
        <AlertDescription>
          返品番号 {refundNo} で {TENDER_LABEL[tender]} に {yen(total)} を払い戻しました。
        </AlertDescription>
      </Alert>

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-[minmax(0,1fr)_22rem]">
        <Card>
          <CardHeader>
            <CardTitle className="text-base">返品内容（確定）</CardTitle>
            <CardDescription>元取引 {sale.txNo}{noReceipt ? "（ノーレシート）" : ""}</CardDescription>
          </CardHeader>
          <CardContent>
            <ul className="divide-y">
              {returning.map((l) => (
                <li key={l.id} className="flex items-center justify-between gap-3 py-2">
                  <div className="flex flex-col">
                    <span className="text-sm font-medium">{l.name}</span>
                    <span className="text-xs text-muted-foreground">
                      ×{l.qtyReturn} · {l.reason ? REASON_LABEL[l.reason] : "—"} · {DISPOSITION_LABEL[l.disposition]}
                    </span>
                  </div>
                  <Delta
                    value={-lineRefund(l)}
                    format={(n) => yen(Math.abs(n))}
                    labels={{ negative: "返金" }}
                    hideArrow
                  />
                </li>
              ))}
            </ul>
          </CardContent>
        </Card>

        <aside className="flex flex-col gap-6">
          <Card>
            <CardContent className="flex flex-col gap-4 pt-6">
              <Statistic
                label="払戻合計"
                value={`− ${yen(total)}`}
                hint={`${TENDER_LABEL[tender]} へ返金`}
                tone="negative"
              />
              <Separator />
              <Button variant="outline" onClick={onPrint} className="w-full">
                <IconPrinter className="h-4 w-4" aria-hidden />
                返品レシートを再印刷
              </Button>
              <Button variant="default" onClick={onReset} className="w-full">
                <IconPackageImport className="h-4 w-4" aria-hidden />
                次の返品を処理
              </Button>
            </CardContent>
          </Card>
        </aside>
      </div>
    </div>
  );
}
